insert into public.cultivars (fruit_id, name_ja, name_en, slug, origin, description, fruit_size, taste, texture, aroma, harvest_season, tree_vigor, difficulty, okinawa_suitability, container_suitability, beginner_suitability, kenyu_comment, public_notes, private_notes, is_public, is_for_sale) values ((select id from public.fruits where slug = 'banana'), 'チュオイタイ', 'Chuoi Tay', 'chuoi-tay', 'ベトナム', 'チュオイタイはベトナムに関連するデザート・調理兼用タイプのバナナです。ナムワ系の素朴な甘さの品種として、家庭栽培では株の大きさ、風対策、病害への注意を見ながら比較したい品種です。', '中ぶり。草姿: 中型。', 'ナムワ系の素朴な甘さ。', 'もっちり', '穏やか', '沖縄では加温なしでも周年的に生育しやすいが、収穫時期は植え付け時期・株の充実・冬越し条件で変動。', '中型。家庭栽培での管理サイズ: 中。', '用途: デザート・調理兼用。耐寒性目安: 強め。バナナセセリ、バンチートップ、パナマ病、台風による倒伏に注意。', '沖縄では露地・庭植えの候補になりますが、台風対策、排水、株元の保護が重要です。比較的作りやすい候補として試しやすい。', '大鉢なら試せるが、肥料切れと乾燥で果実品質が落ちやすい。', '調理用品種として目的を決めて育てたい。完熟生食だけを期待すると印象が変わる。', 'チュオイタイは「デザート・調理兼用」として見比べたい品種。沖縄では味だけでなく、株の大きさ、風への強さ、収穫後の追熟まで含めて評価したいです。', null, 'https://www.promusa.org/Pisang+Awak / 補助: https://www.promusa.org/Diversity+of+banana+cultivars+portal', true, false) on conflict (fruit_id, slug) do nothing;
insert into public.cultivars (fruit_id, name_ja, name_en, slug, origin, description, fruit_size, taste, texture, aroma, harvest_season, tree_vigor, difficulty, okinawa_suitability, container_suitability, beginner_suitability, kenyu_comment, public_notes, private_notes, is_public, is_for_sale) values ((select id from public.fruits where slug = 'banana'), 'クルアイカイ', 'Kluai Khai', 'kluai-khai', 'タイ', 'クルアイカイはタイに関連するデザートタイプのバナナです。濃い甘みで香りがよいの品種として、家庭栽培では株の大きさ、風対策、病害への注意を見ながら比較したい品種です。', '小ぶり。草姿: 小型。', '濃い甘みで香りがよい。', 'なめらか', '甘い香り', '沖縄では加温なしでも周年的に生育しやすいが、収穫時期は植え付け時期・株の充実・冬越し条件で変動。', '小型。家庭栽培での管理サイズ: 低。', '用途: デザート。耐寒性目安: 普通。バナナセセリ、バンチートップ、パナマ病、台風による倒伏に注意。', '沖縄では露地・庭植えの候補になりますが、台風対策、排水、株元の保護が重要です。低めの株なので家庭菜園や鉢でも管理しやすい。', '鉢栽培でも検討しやすい。根詰まりと水切れに注意し、毎年の株分け候補を見ておく。', '家庭栽培では防風・肥培管理・収穫後の追熟を意識すると楽しみやすい。', 'クルアイカイは「デザート」として見比べたい品種。沖縄では味だけでなく、株の大きさ、風への強さ、収穫後の追熟まで含めて評価したいです。', null, 'https://plantuse.plantnet.org/en/Musa_(PROSEA_Fruits) / 補助: https://www.promusa.org/Diversity+of+banana+cultivars+portal', true, false) on conflict (fruit_id, slug) do nothing;
insert into public.cultivars (fruit_id, name_ja, name_en, slug, origin, description, fruit_size, taste, texture, aroma, harvest_season, tree_vigor, difficulty, okinawa_suitability, container_suitability, beginner_suitability, kenyu_comment, public_notes, private_notes, is_public, is_for_sale) values ((select id from public.fruits where slug = 'banana'), 'クルアイホームトーン', 'Kluai Hom Thong', 'kluai-hom-thong', 'タイ', 'クルアイホームトーンはタイに関連するデザートタイプのバナナです。香りのよい甘さの品種として、家庭栽培では株の大きさ、風対策、病害への注意を見ながら比較したい品種です。', '中ぶり。草姿: 中型。', '香りのよい甘さ。', 'なめらか', '芳香', '沖縄では加温なしでも周年的に生育しやすいが、収穫時期は植え付け時期・株の充実・冬越し条件で変動。', '中型。家庭栽培での管理サイズ: 中。', '用途: デザート。耐寒性目安: 普通。バナナセセリ、バンチートップ、パナマ病、台風による倒伏に注意。', '沖縄では露地・庭植えの候補になりますが、台風対策、排水、株元の保護が重要です。', '大鉢なら試せるが、肥料切れと乾燥で果実品質が落ちやすい。', '家庭栽培では防風・肥培管理・収穫後の追熟を意識すると楽しみやすい。', 'クルアイホームトーンは「デザート」として見比べたい品種。沖縄では味だけでなく、株の大きさ、風への強さ、収穫後の追熟まで含めて評価したいです。', null, 'https://plantuse.plantnet.org/en/Musa_(PROSEA_Fruits) / 補助: https://www.promusa.org/Diversity+of+banana+cultivars+portal', true, false) on conflict (fruit_id, slug) do nothing;
insert into public.cultivars (fruit_id, name_ja, name_en, slug, origin, description, fruit_size, taste, texture, aroma, harvest_season, tree_vigor, difficulty, okinawa_suitability, container_suitability, beginner_suitability, kenyu_comment, public_notes, private_notes, is_public, is_for_sale) values ((select id from public.fruits where slug = 'banana'), 'クルアイレップムーナン', 'Kluai Leb Mu Nang', 'kluai-leb-mu-nang', 'タイ', 'クルアイレップムーナンはタイに関連するデザートタイプのバナナです。甘みが強く香るの品種として、家庭栽培では株の大きさ、風対策、病害への注意を見ながら比較したい品種です。', '小ぶり。草姿: 小型。', '甘みが強く香る。', 'なめらか', '甘い香り', '沖縄では加温なしでも周年的に生育しやすいが、収穫時期は植え付け時期・株の充実・冬越し条件で変動。', '小型。家庭栽培での管理サイズ: 低。', '用途: デザート。耐寒性目安: 普通。バナナセセリ、バンチートップ、パナマ病、台風による倒伏に注意。', '沖縄では露地・庭植えの候補になりますが、台風対策、排水、株元の保護が重要です。低めの株なので家庭菜園や鉢でも管理しやすい。', '鉢栽培でも検討しやすい。根詰まりと水切れに注意し、毎年の株分け候補を見ておく。', '家庭栽培では防風・肥培管理・収穫後の追熟を意識すると楽しみやすい。', 'クルアイレップムーナンは「デザート」として見比べたい品種。沖縄では味だけでなく、株の大きさ、風への強さ、収穫後の追熟まで含めて評価したいです。', null, 'https://plantuse.plantnet.org/en/Musa_(PROSEA_Fruits) / 補助: https://www.promusa.org/Diversity+of+banana+cultivars+portal', true, false) on conflict (fruit_id, slug) do nothing;
insert into public.cultivars (fruit_id, name_ja, name_en, slug, origin, description, fruit_size, taste, texture, aroma, harvest_season, tree_vigor, difficulty, okinawa_suitability, container_suitability, beginner_suitability, kenyu_comment, public_notes, private_notes, is_public, is_for_sale) values ((select id from public.fruits where slug = 'banana'), 'クルアイハクムック', 'Kluai Hak Muk', 'kluai-hak-muk', 'タイ', 'クルアイハクムックはタイに関連する調理用タイプのバナナです。加熱で甘みが出るの品種として、家庭栽培では株の大きさ、風対策、病害への注意を見ながら比較したい品種です。', '太め。草姿: 大型。', '加熱で甘みが出る。', 'ほくほく', '穏やか', '沖縄では加温なしでも周年的に生育しやすいが、収穫時期は植え付け時期・株の充実・冬越し条件で変動。', '大型。家庭栽培での管理サイズ: 中。', '用途: 調理用。耐寒性目安: 普通。バナナセセリ、バンチートップ、パナマ病、台風による倒伏に注意。', '沖縄では露地・庭植えの候補になりますが、台風対策、排水、株元の保護が重要です。', '大鉢なら試せるが、肥料切れと乾燥で果実品質が落ちやすい。', '調理用品種として目的を決めて育てたい。完熟生食だけを期待すると印象が変わる。', 'クルアイハクムックは「調理用」として見比べたい品種。沖縄では味だけでなく、株の大きさ、風への強さ、収穫後の追熟まで含めて評価したいです。', null, 'https://plantuse.plantnet.org/en/Musa_(PROSEA_Fruits) / 補助: https://www.promusa.org/Diversity+of+banana+cultivars+portal', true, false) on conflict (fruit_id, slug) do nothing;
insert into public.cultivars (fruit_id, name_ja, name_en, slug, origin, description, fruit_size, taste, texture, aroma, harvest_season, tree_vigor, difficulty, okinawa_suitability, container_suitability, beginner_suitability, kenyu_comment, public_notes, private_notes, is_public, is_for_sale) values ((select id from public.fruits where slug = 'banana'), 'クルアイヒン', 'Kluai Hin', 'kluai-hin', 'タイ', 'クルアイヒンはタイに関連する調理用タイプのバナナです。加熱向きで腹持ちがよいの品種として、家庭栽培では株の大きさ、風対策、病害への注意を見ながら比較したい品種です。', '太め。草姿: 大型。', '加熱向きで腹持ちがよい。', 'ほくほく', '穏やか', '沖縄では加温なしでも周年的に生育しやすいが、収穫時期は植え付け時期・株の充実・冬越し条件で変動。', '大型。家庭栽培での管理サイズ: 高。', '用途: 調理用。耐寒性目安: 普通。バナナセセリ、バンチートップ、パナマ病、台風による倒伏に注意。', '沖縄では露地・庭植えの候補になりますが、台風対策、排水、株元の保護が重要です。大株になりやすく、防風と十分な株間を確保したい。', '鉢では長期維持が難しいため、露地または大鉢で短期更新を前提にしたい。', '調理用品種として目的を決めて育てたい。完熟生食だけを期待すると印象が変わる。', 'クルアイヒンは「調理用」として見比べたい品種。沖縄では味だけでなく、株の大きさ、風への強さ、収穫後の追熟まで含めて評価したいです。', null, 'https://plantuse.plantnet.org/en/Musa_(PROSEA_Fruits) / 補助: https://www.promusa.org/Diversity+of+banana+cultivars+portal', true, false) on conflict (fruit_id, slug) do nothing;
insert into public.cultivars (fruit_id, name_ja, name_en, slug, origin, description, fruit_size, taste, texture, aroma, harvest_season, tree_vigor, difficulty, okinawa_suitability, container_suitability, beginner_suitability, kenyu_comment, public_notes, private_notes, is_public, is_for_sale) values ((select id from public.fruits where slug = 'banana'), 'クルアイナムワコム', 'Kluai Nam Wa Khom', 'kluai-nam-wa-khom', 'タイ', 'クルアイナムワコムはタイに関連するデザート・調理兼用タイプのバナナです。ナムワ系で小さく扱いやすいの品種として、家庭栽培では株の大きさ、風対策、病害への注意を見ながら比較したい品種です。', '中ぶり。草姿: 小型。', 'ナムワ系で小さく扱いやすい。', 'もっちり', '穏やか', '沖縄では加温なしでも周年的に生育しやすいが、収穫時期は植え付け時期・株の充実・冬越し条件で変動。', '小型。家庭栽培での管理サイズ: 低。', '用途: デザート・調理兼用。耐寒性目安: 強め。バナナセセリ、バンチートップ、パナマ病、台風による倒伏に注意。', '沖縄では露地・庭植えの候補になりますが、台風対策、排水、株元の保護が重要です。低めの株なので家庭菜園や鉢でも管理しやすい。比較的作りやすい候補として試しやすい。', '鉢栽培でも検討しやすい。根詰まりと水切れに注意し、毎年の株分け候補を見ておく。', '初心者にも試しやすい候補。まずは排水のよい場所と防風を整える。', 'クルアイナムワコムは「デザート・調理兼用」として見比べたい品種。沖縄では味だけでなく、株の大きさ、風への強さ、収穫後の追熟まで含めて評価したいです。', null, 'https://www.promusa.org/Pisang+Awak / 補助: https://www.promusa.org/Diversity+of+banana+cultivars+portal', true, false) on conflict (fruit_id, slug) do nothing;
