insert into public.cultivars (fruit_id, name_ja, name_en, slug, origin, description, fruit_size, taste, texture, aroma, harvest_season, tree_vigor, difficulty, okinawa_suitability, container_suitability, beginner_suitability, kenyu_comment, public_notes, private_notes, is_public, is_for_sale) values ((select id from public.fruits where slug = 'banana'), 'クルアイナムワマリオン', 'Kluai Nam Wa Mali-Ong', 'kluai-nam-wa-mali-ong', 'タイ', 'クルアイナムワマリオンはタイに関連するデザート・調理兼用タイプのバナナです。香りを楽しむナムワ系の品種として、家庭栽培では株の大きさ、風対策、病害への注意を見ながら比較したい品種です。', '中ぶり。草姿: 中型。', '香りを楽しむナムワ系。', 'もっちり', '甘い香り', '沖縄では加温なしでも周年的に生育しやすいが、収穫時期は植え付け時期・株の充実・冬越し条件で変動。', '中型。家庭栽培での管理サイズ: 中。', '用途: デザート・調理兼用。耐寒性目安: 強め。バナナセセリ、バンチートップ、パナマ病、台風による倒伏に注意。', '沖縄では露地・庭植えの候補になりますが、台風対策、排水、株元の保護が重要です。比較的作りやすい候補として試しやすい。', '大鉢なら試せるが、肥料切れと乾燥で果実品質が落ちやすい。', '調理用品種として目的を決めて育てたい。完熟生食だけを期待すると印象が変わる。', 'クルアイナムワマリオンは「デザート・調理兼用」として見比べたい品種。沖縄では味だけでなく、株の大きさ、風への強さ、収穫後の追熟まで含めて評価したいです。', null, 'https://www.promusa.org/Pisang+Awak / 補助: https://www.promusa.org/Diversity+of+banana+cultivars+portal', true, false) on conflict (fruit_id, slug) do nothing;
insert into public.cultivars (fruit_id, name_ja, name_en, slug, origin, description, fruit_size, taste, texture, aroma, harvest_season, tree_vigor, difficulty, okinawa_suitability, container_suitability, beginner_suitability, kenyu_comment, public_notes, private_notes, is_public, is_for_sale) values ((select id from public.fruits where slug = 'banana'), 'サバ', 'Saba', 'saba', 'フィリピン', 'サバはフィリピンに関連する調理用タイプのバナナです。加熱で甘みが増すの品種として、家庭栽培では株の大きさ、風対策、病害への注意を見ながら比較したい品種です。', '太め。草姿: 大型。', '加熱で甘みが増す。', 'ほくほく', '穏やか', '沖縄では加温なしでも周年的に生育しやすいが、収穫時期は植え付け時期・株の充実・冬越し条件で変動。', '大型。家庭栽培での管理サイズ: 高。', '用途: 調理用。耐寒性目安: 強め。バナナセセリ、バンチートップ、パナマ病、台風による倒伏に注意。', '沖縄では露地・庭植えの候補になりますが、台風対策、排水、株元の保護が重要です。大株になりやすく、防風と十分な株間を確保したい。比較的作りやすい候補として試しやすい。', '鉢では長期維持が難しいため、露地または大鉢で短期更新を前提にしたい。', '調理用品種として目的を決めて育てたい。完熟生食だけを期待すると印象が変わる。', 'サバは「調理用」として見比べたい品種。沖縄では味だけでなく、株の大きさ、風への強さ、収穫後の追熟まで含めて評価したいです。', null, 'https://plantuse.plantnet.org/en/Musa_(PROSEA_Fruits) / 補助: https://www.promusa.org/Diversity+of+banana+cultivars+portal', true, false) on conflict (fruit_id, slug) do nothing;
insert into public.cultivars (fruit_id, name_ja, name_en, slug, origin, description, fruit_size, taste, texture, aroma, harvest_season, tree_vigor, difficulty, okinawa_suitability, container_suitability, beginner_suitability, kenyu_comment, public_notes, private_notes, is_public, is_for_sale) values ((select id from public.fruits where slug = 'banana'), 'カルダバ', 'Cardaba', 'cardaba', 'フィリピン', 'カルダバはフィリピンに関連する調理用タイプのバナナです。加熱向きで食べ応えがあるの品種として、家庭栽培では株の大きさ、風対策、病害への注意を見ながら比較したい品種です。', '太め。草姿: 大型。', '加熱向きで食べ応えがある。', 'ほくほく', '穏やか', '沖縄では加温なしでも周年的に生育しやすいが、収穫時期は植え付け時期・株の充実・冬越し条件で変動。', '大型。家庭栽培での管理サイズ: 高。', '用途: 調理用。耐寒性目安: 強め。バナナセセリ、バンチートップ、パナマ病、台風による倒伏に注意。', '沖縄では露地・庭植えの候補になりますが、台風対策、排水、株元の保護が重要です。大株になりやすく、防風と十分な株間を確保したい。比較的作りやすい候補として試しやすい。', '鉢では長期維持が難しいため、露地または大鉢で短期更新を前提にしたい。', '調理用品種として目的を決めて育てたい。完熟生食だけを期待すると印象が変わる。', 'カルダバは「調理用」として見比べたい品種。沖縄では味だけでなく、株の大きさ、風への強さ、収穫後の追熟まで含めて評価したいです。', null, 'https://plantuse.plantnet.org/en/Musa_(PROSEA_Fruits) / 補助: https://www.promusa.org/Diversity+of+banana+cultivars+portal', true, false) on conflict (fruit_id, slug) do nothing;
insert into public.cultivars (fruit_id, name_ja, name_en, slug, origin, description, fruit_size, taste, texture, aroma, harvest_season, tree_vigor, difficulty, okinawa_suitability, container_suitability, beginner_suitability, kenyu_comment, public_notes, private_notes, is_public, is_for_sale) values ((select id from public.fruits where slug = 'banana'), 'カンダリアン', 'Kandrian', 'kandrian', 'パプアニューギニア', 'カンダリアンはパプアニューギニアに関連する調理用タイプのバナナです。主食利用向きの品種として、家庭栽培では株の大きさ、風対策、病害への注意を見ながら比較したい品種です。', '大型。草姿: 大型。', '主食利用向き。', 'ほくほく', '穏やか', '沖縄では加温なしでも周年的に生育しやすいが、収穫時期は植え付け時期・株の充実・冬越し条件で変動。', '大型。家庭栽培での管理サイズ: 高。', '用途: 調理用。耐寒性目安: 普通。バナナセセリ、バンチートップ、パナマ病、台風による倒伏に注意。', '沖縄では露地・庭植えの候補になりますが、台風対策、排水、株元の保護が重要です。大株になりやすく、防風と十分な株間を確保したい。', '鉢では長期維持が難しいため、露地または大鉢で短期更新を前提にしたい。', '調理用品種として目的を決めて育てたい。完熟生食だけを期待すると印象が変わる。', 'カンダリアンは「調理用」として見比べたい品種。沖縄では味だけでなく、株の大きさ、風への強さ、収穫後の追熟まで含めて評価したいです。', null, 'https://www.promusa.org/Diversity+of+banana+cultivars+portal / 補助: https://www.promusa.org/Diversity+of+banana+cultivars+portal', true, false) on conflict (fruit_id, slug) do nothing;
